const data = $json;
const route = data.routes?.[0];

// If Google has no route data, pass directly to Reka with a flag
if (!route) {
  return [{
    json: {
      origin: $('Webhook').first().json.body.origin,
      destination: $('Webhook').first().json.body.destination,
      city: $('Webhook').first().json.body.city,
      totalDuration: null,
      totalDistance: null,
      steps: [],
      useKnowledgeFallback: true
    }
  }];
}

const leg = route.legs[0];
const steps = leg.steps.map(step => ({
  instruction: step.navigationInstruction?.instructions || '',
  distance: step.distanceMeters ? step.distanceMeters + 'm' : null,
  duration: step.staticDuration || null,
  travelMode: step.travelMode,
  transitDetails: step.transitDetails ? {
    line: step.transitDetails.transitLine?.nameShort || step.transitDetails.transitLine?.name,
    vehicle: step.transitDetails.transitLine?.vehicle?.name,
    departureStop: step.transitDetails.stopDetails?.departureStop?.name,
    arrivalStop: step.transitDetails.stopDetails?.arrivalStop?.name,
    numStops: step.transitDetails.stopCount
  } : null
}));

return [{
  json: {
    origin: $('Webhook').first().json.body.origin,
    destination: $('Webhook').first().json.body.destination,
    city: $('Webhook').first().json.body.city,
    totalDuration: leg.duration || null,
    totalDistance: leg.distanceMeters ? leg.distanceMeters + 'm' : null,
    steps: steps,
    useKnowledgeFallback: false
  }
}];

const response = $json.responses[0].message.content;
const cleaned = response.replace(/```json/g, '').replace(/```/g, '').trim();
let steps = [];
try { steps = JSON.parse(cleaned); } catch(e) {
  const match = cleaned.match(/\[[\s\S]*\]/);
  if (match) { try { steps = JSON.parse(match[0]); } catch { steps = [cleaned]; } }
  else { steps = [cleaned]; }
}

const origin = $('Webhook').first().json.body.origin;
const destination = $('Webhook').first().json.body.destination;
const city = $('Webhook').first().json.body.city;

function formatDuration(d) {
  if (!d) return null;
  const secs = parseInt(String(d).replace(/[^0-9]/g, ''));
  if (isNaN(secs) || secs === 0) return null;
  const mins = Math.round(secs / 60);
  if (mins < 60) return mins + ' mins';
  const hrs = Math.floor(mins / 60);
  const remaining = mins % 60;
  return remaining > 0 ? hrs + ' hr ' + remaining + ' mins' : hrs + ' hr';
}

const rawDuration = $('Google Directions').first().json.routes?.[0]?.legs?.[0]?.duration || null;
let totalDuration = formatDuration(rawDuration);

// Estimate from steps text if Google returned nothing
if (!totalDuration && steps.length > 0) {
  const allText = steps.join(' ').toLowerCase();
  const minuteMatches = allText.match(/(\d+)\s*minute/g) || [];
  const totalMins = minuteMatches.reduce((sum, m) => {
    const n = parseInt(m.match(/\d+/)[0]);
    return sum + n;
  }, 0);
  if (totalMins > 0) totalDuration = '~' + totalMins + ' mins';
}

return [{ 
  json: { origin, destination, city, totalDuration, simplifiedSteps: steps } 
}];

